   Transform obj;Quaternion start_rotation = euler_to_quat((Vector3){0, 5*PI/4, PI/4});Quaternion target_rotation = euler_to_quat((Vector3){0, 0, 0})obj.rotation = start_rotation;float t = 0;// Main loopwhile(1){ ... obj.rotation = quat_slerp(start_rotation, target_rotation, t); t += delta_time; ...}

